  6â†’package kotlinx.datetime.internal.format
  7â†’
  8â†’import kotlinx.datetime.internal.format.formatter.*
  9â†’import kotlinx.datetime.internal.format.parser.*
 10â†’import kotlinx.datetime.internal.isAsciiDigit
 11â†’
 12â†’internal sealed interface FormatStructure<in T> {
 13â†’    fun parser(): ParserStructure<T>
 14â†’    fun formatter(): FormatterStructure<T>
 15â†’}
 16â†’
 17â†’internal class BasicFormatStructure<in T>(
 18â†’    val directive: FieldFormatDirective<T>
 19â†’) : NonConcatenatedFormatStructure<T> {
 20â†’    override fun toString(): String = "BasicFormatStructure($directive)"
 21â†’
 22â†’    override fun equals(other: Any?): Boolean = other is BasicFormatStructure<*> && directive == other.directive
 23â†’    override fun hashCode(): Int = directive.hashCode()
 24â†’
 25â†’    override fun parser(): ParserStructure<T> = directive.parser()
 26â†’    override fun formatter(): FormatterStructure<T> = directive.formatter()
 27â†’}
