125â†’internal class AlternativesParsingFormatStructure<in T>(
126â†’    val mainFormat: FormatStructure<T>,
127â†’    val formats: List<FormatStructure<T>>,
128â†’) : NonConcatenatedFormatStructure<T> {
129â†’    override fun toString(): String = "AlternativesParsing($formats)"
130â†’
131â†’    override fun equals(other: Any?): Boolean =
132â†’        other is AlternativesParsingFormatStructure<*> && mainFormat == other.mainFormat && formats == other.formats
133â†’
134â†’    override fun hashCode(): Int = 31 * mainFormat.hashCode() + formats.hashCode()
135â†’
136â†’    override fun parser(): ParserStructure<T> = ParserStructure(operations = emptyList(), followedBy = buildList {
137â†’        add(mainFormat.parser())
138â†’        for (format in formats) {
139â†’            add(format.parser())
140â†’        }
141â†’    })
142â†’
143â†’    override fun formatter(): FormatterStructure<T> = mainFormat.formatter()
144â†’}
