146â†’internal class OptionalFormatStructure<in T>(
147â†’    val onZero: String,
148â†’    val format: FormatStructure<T>,
149â†’) : NonConcatenatedFormatStructure<T> {
150â†’    override fun toString(): String = "Optional($onZero, $format)"
151â†’
152â†’    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
153â†’        PropertyWithDefault.fromField(field)
154â†’    }
155â†’
156â†’    override fun equals(other: Any?): Boolean =
157â†’        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
158â†’
159â†’    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
160â†’
161â†’    override fun parser(): ParserStructure<T> = ParserStructure(
162â†’        operations = emptyList(),
163â†’        followedBy = listOf(
164â†’            format.parser(),
165â†’            listOf(
166â†’                ConstantFormatStructure<T>(onZero).parser(),
167â†’                ParserStructure(
168â†’                    if (fields.isEmpty()) {
169â†’                        emptyList()
170â†’                    } else {
171â†’                        listOf(
172â†’                            UnconditionalModification {
173â†’                                for (field in fields) {
174â†’                                    field.assignDefault(it)
175â†’                                }
176â†’                            }
177â†’                        )
178â†’                    },
179â†’                    emptyList()
180â†’                )
181â†’            ).concat()
182â†’        )
183â†’    )
184â†’
185â†’    override fun formatter(): FormatterStructure<T> {
186â†’        val formatter = format.formatter()
187â†’        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
188â†’        return if (predicate is Truth) {
189â†’            ConstantStringFormatterStructure(onZero)
190â†’        } else {
191â†’            ConditionalFormatter(
192â†’                listOf(
193â†’                    predicate::test to ConstantStringFormatterStructure(onZero),
194â†’                    Truth::test to formatter
195â†’                )
196â†’            )
197â†’        }
198â†’    }
199â†’
200â†’    private class PropertyWithDefault<in T, E> private constructor(
201â†’        private val accessor: Accessor<T, E>,
202â†’        private val defaultValue: E
203â†’    ) {
204â†’        companion object {
205â†’            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
206â†’                val default = field.defaultValue
207â†’                require(default != null) {
208â†’                    "The field '${field.name}' does not define a default value"
209â†’                }
210â†’                return PropertyWithDefault(field.accessor, default)
211â†’            }
212â†’        }
213â†’
214â†’        inline fun assignDefault(target: T) {
215â†’            accessor.trySetWithoutReassigning(target, defaultValue)
216â†’        }
217â†’
218â†’        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
219â†’    }
220â†’}
221â†’
222â†’internal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
223â†’
224â†’internal open class ConcatenatedFormatStructure<in T>(
225â†’    val formats: List<NonConcatenatedFormatStructure<T>>
226â†’) : FormatStructure<T> {
227â†’    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
228â†’
229â†’    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
230â†’
231â†’    override fun hashCode(): Int = formats.hashCode()
232â†’
233â†’    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
234â†’
235â†’    override fun formatter(): FormatterStructure<T> {
236â†’        val formatters = formats.map { it.formatter() }
237â†’        return if (formatters.size == 1) {
238â†’            formatters.single()
239â†’        } else {
240â†’            ConcatenatedFormatter(formatters)
241â†’        }
242â†’    }
243â†’}
244â†’
245â†’internal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
246â†’    ConcatenatedFormatStructure<T>(formats) {
247â†’    private val cachedFormatter: FormatterStructure<T> = super.formatter()
248â†’    private val cachedParser: ParserStructure<T> = super.parser()
249â†’
250â†’    override fun formatter(): FormatterStructure<T> = cachedFormatter
251â†’
252â†’    override fun parser(): ParserStructure<T> = cachedParser
253â†’}
254â†’
255â†’private fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
256â†’    fun rec(format: FormatStructure<T>) {
257â†’        when (format) {
258â†’            is BasicFormatStructure -> add(format.directive)
259â†’            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
260â†’            is ConstantFormatStructure -> {}
261â†’            is SignedFormatStructure -> rec(format.format)
262â†’            is AlternativesParsingFormatStructure -> {
263â†’                rec(format.mainFormat); format.formats.forEach { rec(it) }
264â†’            }
265â†’
266â†’            is OptionalFormatStructure -> rec(format.format)
267â†’        }
268â†’    }
269â†’    rec(format)
270â†’}
