128â†’private object OffsetFields {
129â†’    private val sign = object : FieldSign<UtcOffsetFieldContainer> {
130â†’        override val isNegative = PropertyAccessor(UtcOffsetFieldContainer::isNegative)
131â†’        override fun isZero(obj: UtcOffsetFieldContainer): Boolean =
132â†’            (obj.totalHoursAbs ?: 0) == 0 && (obj.minutesOfHour ?: 0) == 0 && (obj.secondsOfMinute ?: 0) == 0
133â†’    }
134â†’    val totalHoursAbs = UnsignedFieldSpec(
135â†’        PropertyAccessor(UtcOffsetFieldContainer::totalHoursAbs),
136â†’        defaultValue = 0,
137â†’        minValue = 0,
138â†’        maxValue = 18,
139â†’        sign = sign,
140â†’    )
141â†’    val minutesOfHour = UnsignedFieldSpec(
142â†’        PropertyAccessor(UtcOffsetFieldContainer::minutesOfHour),
143â†’        defaultValue = 0,
144â†’        minValue = 0,
145â†’        maxValue = 59,
146â†’        sign = sign,
147â†’    )
148â†’    val secondsOfMinute = UnsignedFieldSpec(
149â†’        PropertyAccessor(UtcOffsetFieldContainer::secondsOfMinute),
150â†’        defaultValue = 0,
151â†’        minValue = 0,
152â†’        maxValue = 59,
153â†’        sign = sign,
154â†’    )
155â†’}
