157â†’internal class IncompleteUtcOffset(
158â†’    override var isNegative: Boolean? = null,
159â†’    override var totalHoursAbs: Int? = null,
160â†’    override var minutesOfHour: Int? = null,
161â†’    override var secondsOfMinute: Int? = null,
162â†’) : UtcOffsetFieldContainer, Copyable<IncompleteUtcOffset> {
163â†’
164â†’    fun toUtcOffset(): UtcOffset {
165â†’        val sign = if (isNegative == true) -1 else 1
166â†’        return UtcOffset(
167â†’            totalHoursAbs?.let { it * sign }, minutesOfHour?.let { it * sign }, secondsOfMinute?.let { it * sign }
168â†’        )
169â†’    }
170â†’
171â†’    fun populateFrom(offset: UtcOffset) {
172â†’        isNegative = offset.totalSeconds < 0
173â†’        val totalSecondsAbs = offset.totalSeconds.absoluteValue
174â†’        totalHoursAbs = totalSecondsAbs / 3600
175â†’        minutesOfHour = (totalSecondsAbs / 60) % 60
176â†’        secondsOfMinute = totalSecondsAbs % 60
177â†’    }
178â†’
179â†’    override fun equals(other: Any?): Boolean =
180â†’        other is IncompleteUtcOffset && isNegative == other.isNegative && totalHoursAbs == other.totalHoursAbs &&
181â†’            minutesOfHour == other.minutesOfHour && secondsOfMinute == other.secondsOfMinute
182â†’
183â†’    override fun hashCode(): Int =
184â†’        isNegative.hashCode() + totalHoursAbs.hashCode() + minutesOfHour.hashCode() + secondsOfMinute.hashCode()
185â†’
186â†’    override fun copy(): IncompleteUtcOffset =
187â†’        IncompleteUtcOffset(isNegative, totalHoursAbs, minutesOfHour, secondsOfMinute)
188â†’
189â†’    override fun toString(): String =
190â†’        "${isNegative?.let { if (it) "-" else "+" } ?: " "}${totalHoursAbs ?: "??"}:${minutesOfHour ?: "??"}:${secondsOfMinute ?: "??"}"
191â†’}
