224â†’private class UtcOffsetSecondOfMinuteDirective(private val padding: Padding) :
225â†’    UnsignedIntFieldFormatDirective<UtcOffsetFieldContainer>(
226â†’        OffsetFields.secondsOfMinute,
227â†’        minDigits = padding.minDigits(2), spacePadding = padding.spaces(2)
228â†’    ) {
