{"content":"package kotlinx.datetime.format

import kotlinx.datetime.*
import kotlin.test.*

class ReproductionTest {
    @Test
    fun testAlternativeParsingFormatting() {
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            alternativeParsing({}) {
                char(' ')
            }
            alternativeParsing(
                { timeZoneId() },
                { offset(UtcOffset.Formats.ISO) }
            ) {
                offsetHours()
                char(':')
                offsetMinutesOfHour()
                optional {
                    char(':')
                    offsetSecondsOfMinute()
                }
            }
        }

        val zone = TimeZone.of("Europe/Berlin")
        val value = Instant.parse("2023-10-20T18:00:00Z")
        val result = readableFormat.format {
            setDateTime(value.toLocalDateTime(zone))
            timeZoneId = zone.id
        }
        assertEquals("2023-10-20 20:00:00 Europe/Berlin", result)
    }

    @Test
    fun testIsoDateTimeOffsetWithShortOffset() {
        val format = DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET
        val result = format.format {
            setDateTime(LocalDateTime(2023, 10, 20, 20, 0, 0))
            offsetHours = 3
        }
        assertEquals("2023-10-20T20:00:00+03", result)
    }
}
