157â†’internal class IncompleteUtcOffset(
158â†’    override var isNegative: Boolean? = null,
159â†’    override var totalHoursAbs: Int? = null,
160â†’    override var minutesOfHour: Int? = null,
161â†’    override var secondsOfMinute: Int? = null,
