179â†’    override fun equals(other: Any?): Boolean =
180â†’        other is IncompleteUtcOffset && isNegative == other.isNegative && totalHoursAbs == other.totalHoursAbs &&
181â†’            minutesOfHour == other.minutesOfHour && secondsOfMinute == other.secondsOfMinute
