183â†’    override fun hashCode(): Int =
184â†’        isNegative.hashCode() + totalHoursAbs.hashCode() + minutesOfHour.hashCode() + secondsOfMinute.hashCode()
185â†’
186â†’    override fun copy(): IncompleteUtcOffset =
187â†’        IncompleteUtcOffset(isNegative, totalHoursAbs, minutesOfHour, secondsOfMinute)
188â†’
189â†’    override fun toString(): String =
190â†’        "${isNegative?.let { if (it) "-" else "+" } ?: " "}${totalHoursAbs ?: "??"}:${minutesOfHour ?: "??"}:${secondsOfMinute ?: "??"}"
191â†’}
