 20â†’internal class UnsignedIntFormatterStructure<in T>(
 21â†’    private val number: (T) -> Int,
 22â†’    private val zeroPadding: Int,
 23â†’): FormatterStructure<T> {
 24â†’
 25â†’    init {
 26â†’        require(zeroPadding >= 0) { "The minimum number of digits ($zeroPadding) is negative" }
 27â†’        require(zeroPadding <= 9) { "The minimum number of digits ($zeroPadding) exceeds the length of an Int" }
 28â†’    }
 29â†’
 30â†’    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
 31â†’        val num = number(obj)
 32â†’        val numberStr = num.toString()
 33â†’        repeat(zeroPadding - numberStr.length) { builder.append('0') }
 34â†’        builder.append(numberStr)
 35â†’    }
 36â†’}
