 38â†’internal class SignedIntFormatterStructure<in T>(
 39â†’    private val number: (T) -> Int,
 40â†’    private val zeroPadding: Int,
 41â†’    private val outputPlusOnExceededWidth: Int?,
 42â†’): FormatterStructure<T> {
 43â†’
 44â†’    init {
 45â†’        require(zeroPadding >= 0) { "The minimum number of digits ($zeroPadding) is negative" }
 46â†’        require(zeroPadding <= 9) { "The minimum number of digits ($zeroPadding) exceeds the length of an Int" }
 47â†’    }
 48â†’
 49â†’    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
 50â†’        val innerBuilder = StringBuilder()
 51â†’        val number = number(obj).let { if (minusNotRequired && it < 0) -it else it }
 52â†’        if (outputPlusOnExceededWidth != null && number >= POWERS_OF_TEN[outputPlusOnExceededWidth]) {
 53â†’            innerBuilder.append('+')
 54â†’        }
 55â†’        if (number.absoluteValue < POWERS_OF_TEN[zeroPadding - 1]) {
 56â†’            // needs padding
 57â†’            if (number >= 0) {
 58â†’                innerBuilder.append((number + POWERS_OF_TEN[zeroPadding])).deleteAt(0)
 59â†’            } else {
 60â†’                innerBuilder.append((number - POWERS_OF_TEN[zeroPadding])).deleteAt(1)
 61â†’            }
 62â†’        } else {
 63â†’            innerBuilder.append(number)
 64â†’        }
 65â†’        builder.append(innerBuilder)
 66â†’    }
 67â†’}
